import{_ as a,o as t,c as n,j as r,a as p,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"滑步大师","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/运动类/滑步大师.md","filePath":"4.资源分区/6.技艺及称号/运动类/滑步大师.md"}'),o={name:"4.资源分区/6.技艺及称号/运动类/滑步大师.md"};function d(b,e,l,_,i,c){return t(),n("div",null,[...e[0]||(e[0]=[r("h1",{id:"滑步大师",tabindex:"-1"},[p("滑步大师 "),r("a",{class:"header-anchor",href:"#滑步大师","aria-label":'Permalink to "滑步大师"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌031")])])],-1),s('<h1 id="滑步大师-1" tabindex="-1">滑步大师 <a class="header-anchor" href="#滑步大师-1" aria-label="Permalink to &quot;滑步大师&quot;">​</a></h1><p>滑步大师<br> 购买前提：建卡智力不高于2，或建卡敏捷不低于3<br> 价格：D+500</p><p>“不要傻站着，保持移动，才能降低敌人命中你的概率”<br> “长官！那如果敌人预判了我们的提前量怎么办”<br> “问得好，士兵，这就需要你们发挥自己的主观能动性了。切记，要保持灵活多变的移动方式！不要给敌人预判你们行动轨迹的机会”<br> “了解了，长官！”</p><p>购买本称号后，解锁下属技能的购买权。</p><p>一切的一切，都要从你捡到了这本《滑步大师速成》开始，或许你深信不疑，或者你闲来无事准备挑战你的极限。总之，一段奇妙的经历要开始了！<br> 由于你勤勉锻炼自己的平衡能力与爆发力，你现在掌握了瞬时腾挪身躯的能力。<br> 每轮一次，在你进行一次移动/攻击/招式后，你可以自由动作进行一次【滑步】，令你接下来往某一方向移动15M，但这不意味着你可以不受影响的越过障碍，除非你有别的相关能力。</p><p>————【下属技能】————<br> “滑铲！”<br> 价格：D+500<br> 压低身形，以近乎贴近地面的姿势在战场中穿梭，让那些习惯预瞄爆头线的新人狙击手好好上一课吧！<br> 每轮一次，当你使用【滑步】进行移动后，本轮内你获得6点抵高速，并且获得2点闪避防御。</p><p>战场舞者<br> 价格：D+500<br> 你的背影是如此的潇洒，即使身处战场之中，依旧能看到你那在枪林弹雨中平稳滑步的身影。<br> 现在，你每轮最多进行两次【滑步】而非一次。</p><p>“后撤步！”<br> 价格：C+1000<br> 集中注意...后撤躲闪！迅速离开敌人的射击窗口，规避敌人潜在的CBQ战术，回到掩体之中。<br> 每轮一次，当你在回合外受到攻击时，若你仍保留了【滑步】的使用次数，你可以反射动作进行一次滑步并令这次【滑步】具有打断性。<br> 你每轮额外获得2点AP以转化反射动作。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',10)])])}const m=a(o,[["render",d]]);export{f as __pageData,m as default};
